30	/// Returns the set of tasks whose input globs match at least one changed file.
31	///
32	/// Iterates every task in the engine regardless of which packages are
33	/// "affected" at the package level. This is critical for correctness:
34	/// a task in a non-affected package may declare `$TURBO_ROOT$` inputs
35	/// (resolved to `../../` globs) that reference changed root-level files.
36	///
37	/// The returned map associates each affected task with the repo-relative
38	/// path of the first file that matched its inputs. Callers that don't
39	/// need the file path can discard the values.
40	///
41	/// Does NOT include transitive dependents. Callers should propagate
42	/// through the task graph separately if needed.
43	pub fn match_tasks_against_changed_files(
44	    engine: &Engine<Built, TaskDefinition>,
45	    pkg_dep_graph: &PackageGraph,
46	    changed_files: &HashSet<AnchoredSystemPathBuf>,
47	) -> HashMap<TaskId<'static>, String> {
48	    let mut matched = HashMap::new();
49	
50	    // Pre-convert all file paths to Unix strings once, avoiding repeated
51	    // allocation in the O(tasks × files) inner loop.
52	    let changed_unix: Vec<String> = changed_files
53	        .iter()
54	        .map(|f| f.to_unix().to_string())
55	        .collect();
56	
57	    // Compile globs once per unique (package_path, inputs) pair.
58	    let mut compiled_cache: HashMap<(String, TaskInputs), _> = HashMap::new();
59	
60	    for task_id in engine.task_ids() {
61	        let pkg_name = PackageName::from(task_id.package());
62	        let Some(pkg_dir) = pkg_dep_graph.package_dir(&pkg_name) else {
63	            continue;
64	        };
65	        let pkg_unix = pkg_dir.to_unix();
66	        let pkg_str = pkg_unix.to_string();
67	
68	        let inputs = engine
69	            .task_definition(task_id)
70	            .map(|def| &def.inputs)
71	            .unwrap_or(&DEFAULT_TASK_INPUTS);
72	
73	        let cache_key = (pkg_str.clone(), inputs.clone());
74	        let compiled = compiled_cache
75	            .entry(cache_key)
76	            .or_insert_with(|| compile_globs(inputs));
77	
78	        let pkg_prefix_slash = if pkg_str.is_empty() {
79	            String::new()
80	        } else {
81	            format!("{pkg_str}/")
82	        };
83	
84	        for file_unix in &changed_unix {
85	            if file_matches_compiled_inputs(file_unix, &pkg_str, &pkg_prefix_slash, compiled) {
86	                matched.insert(task_id.clone(), file_unix.clone());
87	                break;
88	            }
89	        }
90	    }
91	
92	    matched
93	}
