142	/// The base task set before `...` expansion.
143	///
144	/// Combines name/directory matching (package-level) with git-range matching
145	/// (task-level via inputs). When both are present, the result is their
146	/// intersection (same semantics as the package-level filter).
147	fn resolve_base_tasks(
148	    engine: &Engine,
149	    selector: &TargetSelector,
150	    pkg_dep_graph: &PackageGraph,
151	    scm: &SCM,
152	    repo_root: &AbsoluteSystemPath,
153	    global_deps: &[String],
154	) -> Result<HashSet<TaskId<'static>>, crate::run::error::Error> {
155	    let tasks_from_packages = resolve_name_and_dir(engine, selector, pkg_dep_graph);
156	    let tasks_from_git_range =
157	        resolve_git_range(engine, selector, pkg_dep_graph, scm, repo_root, global_deps)?;
158	
159	    match (tasks_from_packages, tasks_from_git_range) {
160	        (Some(pkg_tasks), Some(git_tasks)) => {
161	            // Intersection: task must match both name/dir AND git range.
162	            Ok(pkg_tasks.intersection(&git_tasks).cloned().collect())
163	        }
164	        (Some(tasks), None) | (None, Some(tasks)) => Ok(tasks),
165	        (None, None) => Ok(HashSet::new()),
166	    }
167	}
168	
169	/// Matches tasks by package name pattern and/or directory.
170	/// Returns None if the selector has no name/directory constraints.
171	fn resolve_name_and_dir(
172	    engine: &Engine,
173	    selector: &TargetSelector,
174	    pkg_dep_graph: &PackageGraph,
175	) -> Option<HashSet<TaskId<'static>>> {
176	    let has_name = !selector.name_pattern.is_empty();
177	    let has_dir = selector.parent_dir.is_some();
178	
179	    if !has_name && !has_dir {
180	        return None;
181	    }
182	
183	    let matching_packages = find_matching_packages(selector, pkg_dep_graph);
184	    Some(engine.task_ids_for_packages(&matching_packages))
185	}
186	
187	/// Finds packages matching a selector's name pattern and/or directory.
188	fn find_matching_packages(
189	    selector: &TargetSelector,
190	    pkg_dep_graph: &PackageGraph,
191	) -> HashSet<PackageName> {
192	    let mut packages: HashSet<PackageName> = HashSet::new();
193	
194	    // Directory matching
195	    if let Some(parent_dir) = &selector.parent_dir {
196	        let parent_dir_unix = parent_dir.to_unix();
197	        if let Ok(globber) = wax::Glob::new(parent_dir_unix.as_str()) {
198	            let root_anchor = AnchoredSystemPathBuf::from_raw(".").expect("valid anchored");
199	            if parent_dir == &root_anchor {
200	                packages.insert(PackageName::Root);
201	            } else {
202	                for (name, info) in pkg_dep_graph.packages() {
203	                    if globber.is_match(info.package_path().as_path()) {
204	                        packages.insert(name.clone());
205	                    }
206	                }
207	            }
208	        }
209	    } else {
210	        // Start with all packages when only name pattern is used
211	        packages = pkg_dep_graph
212	            .packages()
213	            .map(|(name, _)| name.clone())
214	            .collect();
215	    }
216	
217	    // Name pattern matching
218	    if !selector.name_pattern.is_empty() {
219	        if let Ok(matcher) = turborepo_scope::simple_glob::SimpleGlob::new(&selector.name_pattern) {
220	            use turborepo_scope::simple_glob::Match;
221	            packages.retain(|name| matcher.is_match(name.as_ref()));
222	        }
223	    }
224	
225	    packages
226	}
227	
228	/// Matches tasks by git range using task-level input matching.
229	/// Returns None if the selector has no git range.
230	fn resolve_git_range(
231	    engine: &Engine,
232	    selector: &TargetSelector,
233	    pkg_dep_graph: &PackageGraph,
234	    scm: &SCM,
235	    repo_root: &AbsoluteSystemPath,
236	    global_deps: &[String],
237	) -> Result<Option<HashSet<TaskId<'static>>>, crate::run::error::Error> {
238	    let git_range = match &selector.git_range {
239	        Some(range) => range,
240	        None => return Ok(None),
241	    };
242	
243	    let changed_files = get_changed_files(scm, repo_root, git_range)?;
244	
245	    match changed_files {
246	        Ok(files) => {
247	            let affected = crate::task_change_detector::affected_task_ids(
248	                engine,
249	                pkg_dep_graph,
250	                &files,
251	                global_deps,
252	            );
253	            Ok(Some(affected))
254	        }
255	        Err(e) => {
256	            tracing::warn!(
257	                error = ?e,
258	                "SCM returned invalid change set for filter git range; including all tasks"
259	            );
260	            // If we can't determine changes, include all tasks (safe fallback).
261	            Ok(Some(engine.task_ids().cloned().collect()))
262	        }
263	    }
264	}
265	
266	/// Resolves `match_dependencies` selectors (e.g. `web...[main]`).
267	///
268	/// Finds tasks in the named packages (or their task-graph dependencies)
269	/// whose inputs match the changed files.
270	fn resolve_match_dependencies(
271	    engine: &Engine,
272	    selector: &TargetSelector,
273	    pkg_dep_graph: &PackageGraph,
274	    scm: &SCM,
275	    repo_root: &AbsoluteSystemPath,
276	    global_deps: &[String],
277	) -> Result<HashSet<TaskId<'static>>, crate::run::error::Error> {
278	    let git_range = match &selector.git_range {
279	        Some(range) => range,
280	        None => return Ok(HashSet::new()),
281	    };
282	
283	    // Find all tasks in the named packages
284	    let matching_packages = find_matching_packages(selector, pkg_dep_graph);
285	    let package_tasks = engine.task_ids_for_packages(&matching_packages);
286	
287	    // Expand to include all task-graph dependencies
288	    let mut candidate_tasks = engine.collect_task_dependencies(&package_tasks);
289	    if !selector.exclude_self {
290	        candidate_tasks.extend(package_tasks);
291	    }
292	
293	    // Now check which of these candidates are affected by the git range
294	    let changed_files = get_changed_files(scm, repo_root, git_range)?;
295	
296	    match changed_files {
297	        Ok(files) => {
298	            let affected = crate::task_change_detector::affected_task_ids(
299	                engine,
300	                pkg_dep_graph,
301	                &files,
302	                global_deps,
303	            );
304	            // Intersection: task must be in the candidate set AND affected
305	            Ok(candidate_tasks.intersection(&affected).cloned().collect())
306	        }
307	        Err(_) => {
308	            // Can't determine changes → return all candidates
309	            Ok(candidate_tasks)
310	        }
311	    }
312	}
313	
314	fn get_changed_files(
315	    scm: &SCM,
316	    repo_root: &AbsoluteSystemPath,
317	    git_range: &GitRange,
318	) -> Result<
319	    Result<HashSet<AnchoredSystemPathBuf>, turborepo_scm::git::InvalidRange>,
320	    crate::run::error::Error,
321	> {
322	    let result = scm.changed_files(
323	        repo_root,
324	        git_range.from_ref.as_deref(),
325	        git_range.to_ref.as_deref(),
326	        git_range.include_uncommitted,
327	        git_range.merge_base,
328	        git_range.allow_unknown_objects,
329	    )?;
330	    Ok(result)
331	}
