18	/// Root-level files that always trigger a full rebuild when changed.
19	///
20	/// - `package.json`: workspace topology or root dependency changes
21	/// - `turbo.json`/`turbo.jsonc`: task definitions, global deps, pipelines
22	///
23	/// Lockfile changes are detected separately via the package manager.
24	const DEFAULT_GLOBAL_DEPS: &[&str] = &["turbo.json", "turbo.jsonc"];
25	
26	/// Determines which tasks are directly affected by the given set of changed
27	/// files. Does NOT include transitive dependents — use
28	/// `Engine::retain_affected_tasks` afterward for that.
29	///
30	/// Checks all tasks against all changed files regardless of package boundaries.
31	/// This is what makes cross-package inputs (`$TURBO_ROOT$/schema/api.json`)
32	/// work correctly.
33	///
34	/// Returns an empty set when no files have changed.
35	///
36	/// # Global changes
37	///
38	/// If any changed file is a global dependency (root config files, lockfile,
39	/// or user-configured `globalDependencies`), all tasks are returned.
40	///
41	/// # Error handling
42	///
43	/// Invalid glob patterns in task `inputs` are logged at `warn` level and
44	/// skipped. If the SCM range is invalid, the caller should handle the
45	/// fallback (typically running all tasks).
46	#[tracing::instrument(skip(engine, pkg_dep_graph, changed_files), fields(
47	    file_count = changed_files.len(),
48	    global_deps = global_deps.len(),
49	))]
50	pub fn affected_task_ids(
51	    engine: &Engine,
52	    pkg_dep_graph: &PackageGraph,
53	    changed_files: &HashSet<AnchoredSystemPathBuf>,
54	    global_deps: &[String],
55	) -> HashSet<TaskId<'static>> {
56	    if is_global_change(changed_files, global_deps, pkg_dep_graph) {
57	        return engine.task_ids().cloned().collect();
58	    }
59	
60	    turborepo_engine::match_tasks_against_changed_files(engine, pkg_dep_graph, changed_files)
61	        .into_keys()
62	        .collect()
63	}
64	
65	/// Returns `true` if any changed file is a global dependency, meaning all
66	/// tasks should be considered affected regardless of their individual inputs.
67	///
68	/// Global changes include:
69	/// - Root config files: `package.json`, `turbo.json`, `turbo.jsonc`
70	/// - The package manager's lockfile
