                .iter()
                .filter(|f| self.repo_root.resolve(f).exists())
                .cloned()
                .collect();

            let total_tasks = engine.task_ids().count();
            let affected_tasks = crate::task_change_detector::affected_task_ids(
                &engine,
                pkg_dep_graph,
                &existing_files,
                &root_turbo_json.global_deps,
