        reachable.insert(n);
    }
});
let entrypoints_and_dependencies: Vec<_> = reachable.iter().copied().collect();
depth_first_search(Reversed(&self.task_graph), entrypoints_and_dependencies, |event| {
    if let DfsEvent::Discover(n, _) = event {
        reachable.insert(n);
    }
});

